import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import logo from '../logo.svg';

function Navbar() {
  const location = useLocation();
  const navItems = [
    { name: 'Home', path: '/' },
    { name: 'Generator', path: '/generator' },
    { name: 'Projects', path: '/projects' },
    { name: 'Docs', path: '/docs' },
    { name: 'Settings', path: '/settings' },
  ];
  return (
    <nav style={{ display: 'flex', alignItems: 'center', background: '#18181b', padding: '0.5rem 2rem', color: 'white' }}>
      <img src={logo} alt="logo" style={{ width: 32, height: 32, marginRight: 12 }} />
      <span style={{ fontWeight: 700, fontSize: 20, marginRight: 32, color: 'white' }}>CodeGen AI</span>
      {navItems.map(item => (
        <Link
          key={item.path}
          to={item.path}
          style={{
            color: location.pathname === item.path ? '#fff' : '#cbd5e1',
            background: location.pathname === item.path ? '#27272a' : 'transparent',
            borderRadius: 8,
            padding: '0.5rem 1rem',
            marginRight: 8,
            textDecoration: 'none',
            fontWeight: 500
          }}
        >
          {item.name}
        </Link>
      ))}
    </nav>
  );
}

export default Navbar;
